ops.content:
plugins {
    id 'com.android.application'
    id 'org.jetbrains.kotlin.android'
}

android {
    namespace "com.speedster"
    compileSdk 34

    defaultConfig {
        applicationId "com.speedster"
        minSdk 24
        targetSdk 34
        versionCode 1
        versionName "1.0"
    }

    buildTypes {
        release {
            minifyEnabled false
        }
    }

    buildFeatures {
        compose true
    }

    composeOptions {
        kotlinCompilerExtensionVersion '1.5.14'
    }
}

// Robust Harvest Task
tasks.register("harvestDeps") {
    doLast {
        def dest = file("build/harvested_libs")
        dest.mkdirs()
        // Use releaseRuntimeClasspath which is the specific one created by AGP
        configurations.releaseRuntimeClasspath.each { file ->
            if (file.name.endsWith(".jar")) {
                copy {
                    from file
                    into dest
                }
            }
        }
    }
}

dependencies {
    implementation 'androidx.core:core-ktx:1.12.0'
    implementation 'androidx.lifecycle:lifecycle-runtime-ktx:2.7.0'
    implementation 'androidx.activity:activity-compose:1.8.2'
    implementation platform('androidx.compose:compose-bom:2024.02.01')
    implementation 'androidx.compose.ui:ui'
    implementation 'androidx.compose.ui:ui-graphics'
    implementation 'androidx.compose.material3:material3'
}

