ops.replace_with:
function triggerBuild() {
    const overlay = document.getElementById('trigger-build-overlay');
    overlay.classList.add('active');
    toggleFab(false);

    // Load suggestions
    const suggestions = JSON.parse(localStorage.getItem('conduit_workflow_history') || '["build.yml", "deploy.yml"]');
    const dl = document.getElementById('workflow-suggestions');
    dl.innerHTML = suggestions.map(s => `<option value="${s}">`).join('');

    document.getElementById('tb-workflow').value = suggestions[0] || 'build.yml';
    document.getElementById('tb-branch').value = 'conduit-dev';
    document.getElementById('tb-workflow').focus();
}

function closeTriggerModal() {
    document.getElementById('trigger-build-overlay').classList.remove('active');
    toggleFab(true);
}

async function executeTriggerBuild() {
    const workflowFile = document.getElementById('tb-workflow').value.trim();
    const branch = document.getElementById('tb-branch').value.trim();
    if (!workflowFile || !branch) return showGlobalToast("Workflow and Branch are required", true);

    // Save to suggestions
    let suggestions = JSON.parse(localStorage.getItem('conduit_workflow_history') || '[]');
    suggestions = [workflowFile, ...suggestions.filter(s => s !== workflowFile)].slice(0, 10);
    localStorage.setItem('conduit_workflow_history', JSON.stringify(suggestions));

    closeTriggerModal();

